// ── THREE.JS ──────────────────────────────────────────────────────────────────
function useThreeScene(canvasRef) {
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(window.innerWidth, window.innerHeight);
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(70, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.position.z = 5;

    // Particles
    const count = 5000;
    const pos = new Float32Array(count * 3);
    for (let i = 0; i < count * 3; i++) pos[i] = (Math.random() - 0.5) * 25;
    const geo = new THREE.BufferGeometry();
    geo.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    const mat = new THREE.PointsMaterial({ size: 0.022, color: 0x00f5ff, transparent: true, opacity: 0.55 });
    scene.add(new THREE.Points(geo, mat));

    // Floating shapes
    const meshes = [];
    const defs = [
      { g: new THREE.IcosahedronGeometry(1.0, 0), c: 0x00f5ff, p: [-4.5, 1.8, -2.5] },
      { g: new THREE.OctahedronGeometry(0.75, 0), c: 0x7b2fff, p: [4.8, -1.5, -2] },
      { g: new THREE.TorusGeometry(0.65, 0.22, 6, 8), c: 0xff2d78, p: [-3.8, -2.2, -3] },
      { g: new THREE.TetrahedronGeometry(0.8, 0), c: 0x00f5ff, p: [4.2, 2.8, -3] },
      { g: new THREE.OctahedronGeometry(0.55, 0), c: 0x7b2fff, p: [0, -3.5, -4] },
    ];
    defs.forEach(({ g, c, p }) => {
      const m = new THREE.MeshBasicMaterial({ color: c, wireframe: true, transparent: true, opacity: 0.3 });
      const mesh = new THREE.Mesh(g, m);
      mesh.position.set(...p);
      scene.add(mesh);
      meshes.push(mesh);
    });

    const mouse = { x: 0, y: 0 };
    const onMouse = e => { mouse.x = (e.clientX / window.innerWidth - 0.5) * 2; mouse.y = -(e.clientY / window.innerHeight - 0.5) * 2; };
    const onResize = () => { camera.aspect = window.innerWidth / window.innerHeight; camera.updateProjectionMatrix(); renderer.setSize(window.innerWidth, window.innerHeight); };
    window.addEventListener("mousemove", onMouse);
    window.addEventListener("resize", onResize);

    let raf;
    const animate = () => {
      raf = requestAnimationFrame(animate);
      const t = Date.now() * 0.001;
      meshes.forEach((m, i) => { m.rotation.x = t * (0.22 + i * 0.06); m.rotation.y = t * (0.15 + i * 0.04); });
      camera.position.x += (mouse.x * 0.35 - camera.position.x) * 0.04;
      camera.position.y += (mouse.y * 0.28 - camera.position.y) * 0.04;
      renderer.render(scene, camera);
    };
    animate();
    return () => { cancelAnimationFrame(raf); window.removeEventListener("mousemove", onMouse); window.removeEventListener("resize", onResize); renderer.dispose(); };
  }, []);
}

